script:
frappe.ui.form.on("Hostel Admission", {
    refresh(frm) {
        if (!frm.is_new()) {
            frm.add_custom_button("View Attendance", function () {
                frappe.set_route("List", "Hostel Attendance", {
                    student: frm.doc.student
                });
            }, "View");
        }
    }
});
